css:
body {
    font-family: Arial, sans-serif;
    font-size: 11pt;
    margin: 0;
    padding: 20px;
    line-height: 1.6;
}

.memo-container {
    max-width: 800px;
    margin: 0 auto;
    border: 2px solid #000;
    padding: 30px;
}

.memo-header {
    text-align: center;
    border-bottom: 2px solid #000;
    padding-bottom: 15px;
    margin-bottom: 20px;
}

.company-name {
    font-size: 18pt;
    font-weight: bold;
    margin-bottom: 5px;
    text-transform: uppercase;
}

.company-address {
    font-size: 9pt;
    line-height: 1.3;
    margin-bottom: 10px;
}

.memo-title {
    font-size: 14pt;
    font-weight: bold;
    margin-top: 10px;
    text-decoration: underline;
}

.memo-info {
    margin-bottom: 20px;
}

.memo-info-row {
    margin-bottom: 8px;
    display: flex;
    justify-content: space-between;
}

.memo-info-label {
    font-weight: bold;
    width: 100px;
    display: inline-block;
}

.memo-section {
    margin-bottom: 20px;
}

.section-heading {
    font-weight: bold;
    font-size: 12pt;
    margin-bottom: 10px;
    border-bottom: 1px solid #333;
    padding-bottom: 5px;
}

.memo-content {
    text-align: justify;
    margin-bottom: 15px;
    line-height: 1.8;
}

.memo-list {
    margin-left: 20px;
    margin-bottom: 15px;
}

.memo-list li {
    margin-bottom: 8px;
}

.signature-section {
    margin-top: 40px;
    page-break-inside: avoid;
}

.signature-block {
    margin-top: 20px;
}

.signature-label {
    font-weight: bold;
    margin-bottom: 5px;
}

.signature-line {
    border-top: 1px solid #000;
    width: 250px;
    margin-top: 50px;
    padding-top: 5px;
}

.signature-date {
    margin-top: 10px;
    font-style: italic;
}

.acknowledgment-section {
    margin-top: 40px;
    padding-top: 20px;
    border-top: 2px dashed #666;
    page-break-inside: avoid;
}

.acknowledgment-title {
    font-weight: bold;
    font-size: 12pt;
    margin-bottom: 15px;
    text-align: center;
}

.acknowledgment-text {
    margin-bottom: 20px;
    line-height: 1.8;
}

.employee-signature {
    margin-top: 30px;
}

.employee-signature-row {
    display: flex;
    justify-content: space-between;
    margin-bottom: 60px;
}

.employee-signature-item {
    width: 45%;
}

.footer-note {
    margin-top: 30px;
    font-size: 9pt;
    font-style: italic;
    color: #666;
    text-align: center;
}

@media print {
    body {
        margin: 0;
        padding: 10px;
    }
    .page-break {
        page-break-before: always;
    }
    .no-print {
        display: none;
    }
}
